#!/bin/bash
echo "=== Setting up Respiratory Multiplex PCR Design task ==="

# Record task start time (anti-gaming)
date +%s > /tmp/task_start_time.txt

# Clean existing state
rm -rf /home/ga/UGENE_Data/multiplex 2>/dev/null || true
mkdir -p /home/ga/UGENE_Data/multiplex/results

# Generate real viral sequences (partial segments, but biologically accurate from NCBI)
# Flu A H1N1 PR8 Segment 7 (M gene) - 1027 bp
cat > /home/ga/UGENE_Data/multiplex/influenza_A_segment7.fasta << 'EOF'
>Influenza_A_segment_7_M1_M2

EOF

# Flu B Lee/40 Segment 8 (NS gene) - 948 bp
cat > /home/ga/UGENE_Data/multiplex/influenza_B_segment8.fasta << 'EOF'
>Influenza_B_segment_8_NS

EOF

# RSV A2 N gene region - 1173 bp
cat > /home/ga/UGENE_Data/multiplex/rsv_genome.fasta << 'EOF'
>RSV_N_gene_partial

EOF

# Set ownership to GA user
chown -R ga:ga /home/ga/UGENE_Data/multiplex

# Start UGENE cleanly
pkill -f "ugene" 2>/dev/null || true
sleep 3
pkill -9 -f "ugene" 2>/dev/null || true
sleep 2

su - ga -c "DISPLAY=:1 XAUTHORITY=/home/ga/.Xauthority setsid /home/ga/launch_ugene.sh &"

# Wait for UGENE to appear
echo "Waiting for UGENE to start..."
for i in {1..30}; do
    if DISPLAY=:1 wmctrl -l 2>/dev/null | grep -qi "ugene\|UGENE\|Unipro"; then
        echo "UGENE is running."
        break
    fi
    sleep 2
done

sleep 5
# Dismiss popups
DISPLAY=:1 xdotool key Escape 2>/dev/null || true
sleep 1

# Maximize the window
WID=$(DISPLAY=:1 wmctrl -l 2>/dev/null | grep -i "ugene\|UGENE\|Unipro" | head -1 | awk '{print $1}')
if [ -n "$WID" ]; then
    DISPLAY=:1 wmctrl -i -r "$WID" -b add,maximized_vert,maximized_horz 2>/dev/null || true
    DISPLAY=:1 wmctrl -i -a "$WID" 2>/dev/null || true
fi

sleep 2

# Take initial screenshot for evidence
DISPLAY=:1 scrot /tmp/task_initial_state.png 2>/dev/null || \
    DISPLAY=:1 import -window root /tmp/task_initial_state.png 2>/dev/null || true

echo "=== Task setup complete ==="